from jinja2.loaders import DictLoader, FileSystemLoader, FunctionLoader, PrefixLoader, ChoiceLoader
from jinja2 import Environment
from jinja2.exceptions import TemplateNotFound

def alias(t):
    return {'home': 'index.html'}.get(t, t)

env = Environment(loader=DictLoader({'index.html': 'hello'}, path_transform=alias))
print(env.get_template('home').render())

try:
    env2 = Environment(loader=DictLoader({'index.html': 'hello'}))
    env2.get_template('home')
except TemplateNotFound as e:
    print('not found ok:', e.name)

def norm(t):
    return t.lstrip('/')

env3 = Environment(loader=DictLoader({'a.html': 'A'}, path_transform=norm))
print(env3.get_template('/a.html').render())

# PrefixLoader test
pl = PrefixLoader({'app1': DictLoader({'x.html': 'X'})}, path_transform=lambda t: t)
env4 = Environment(loader=pl)
print(env4.get_template('app1/x.html').render())

try:
    env4.get_template('app1/missing.html')
except TemplateNotFound as e:
    print('prefix not found ok:', e.name)
"
